sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
  // implement resource here

	var reqBody = request.body.data;
	var sync = new mydesign_util();

	var isValidTicket = sync.checkValidPatchCall(reqBody); //returns if it is a valid ticket and also if it Service Request or Service Incident
	var processInput;

	if(isValidTicket[0]){
		if(isValidTicket[1]=='Service Incident'){
			processInput = sync.transform(reqBody);
		}else if(isValidTicket[1]=='Service Request'){
			processInput = sync.transformRequestUpdate(reqBody,isValidTicket[2]);
		}

		response.setStatus(processInput['status_code']);
		response.setBody(processInput);

		//Attachment API call
			if(reqBody.attachments && processInput['status_code']==200|| processInput['status_code']==201){
				//var attach_id = reqBody.attachments[0].id;
				var attachment_response = sync.getAttachment(reqBody, isValidTicket[1]);
				gs.info(' Ticket PATCH : ' +attachment_response );
			}
	}else{
		var returnBody = {};
		returnBody['status'] ='ignored';
		returnBody['status_code'] = 200;
		returnBody['status_message'] ='Ticket update is ignored as there is no matching record found in ServiceNow system.';
		response.setBody(returnBody);
	}


})(request, response);
